import React, { useState, useEffect } from "react";

const NoteModal = ({ note, isOpen, onClose, onSave }) => {
  // Determine if we are creating a new note (note will be null/undefined)
  const isNewNote = !note || !note.id; 

  // --- STATE MANAGEMENT ---
  const [isEditing, setIsEditing] = useState(isNewNote); // Start editing immediately for a new note
  const [editedTitle, setEditedTitle] = useState(note?.title || "");
  const [editedContent, setEditedContent] = useState(note?.content || "");
  
  // FIX 1: Reset state when 'note' prop changes (Crucial for handling different notes)
  useEffect(() => {
    setEditedTitle(note?.title || "");
    setEditedContent(note?.content || "");
    setIsEditing(isNewNote); 
    // The dependency array ensures this runs whenever 'note' or 'isNewNote' changes
  }, [note, isNewNote]);
  // --- END STATE MANAGEMENT ---

  
  const handleSave = () => {
    if (!editedTitle.trim() && !editedContent.trim()) {
      alert("Note cannot be empty.");
      return;
    }

    onSave({
      ...note, // Retain existing properties like ID, creation date, etc.
      title: editedTitle.trim() || "Untitled Note", // Use 'Untitled' if title is empty
      content: editedContent,
      updatedAt: new Date().toISOString(), // Add an update timestamp
    }); 
    
    // For existing notes, revert to view mode after saving
    if (!isNewNote) {
      setIsEditing(false);
    } else {
      onClose(); // Close after creating a new note
    }
  };

  const handleCancel = () => {
    // If it's a new note, close the modal immediately on cancel
    if (isNewNote) {
      onClose();
      return;
    }
    
    // Revert state to the original note's content
    setEditedTitle(note?.title || "");
    setEditedContent(note?.content || "");
    setIsEditing(false);
  };
  
  // FIX 2: Allow modal to open even if 'note' is null (for new note creation)
  if (!isOpen) return null; 

  return (
    <div
      className="fixed inset-0 bg-black bg-opacity-70 flex items-center justify-center z-50 p-4"
      onClick={isNewNote ? onClose : handleCancel} // Clicking backdrop cancels and closes (or just closes for new note)
    >
      <div
        className="bg-white rounded-xl shadow-2xl max-w-2xl w-full relative" // Increased max-width and added relative
        onClick={(e) => e.stopPropagation()} // Prevent closing when clicking inside
      >
        <div className="p-8"> {/* Added padding to the content area */}
        
          {/* Close Button */}
          <button
            onClick={onClose}
            className="absolute top-4 right-4 text-gray-400 hover:text-gray-700 text-3xl transition-colors"
            aria-label="Close"
          >
            &times; {/* Use &times; for a cleaner 'X' */}
          </button>

          <h2 className="text-3xl font-extrabold text-indigo-600 mb-6">
            {isNewNote ? 'Create New Note' : (isEditing ? 'Edit Note' : note.title)}
          </h2>

          {/* Title Input/Display */}
          {isEditing ? (
            <input
              type="text"
              value={editedTitle}
              onChange={(e) => setEditedTitle(e.target.value)}
              className="w-full text-3xl font-bold text-gray-800 mb-4 pb-2 border-b-2 border-gray-200 focus:border-indigo-500 outline-none"
              placeholder="Note Title"
              autoFocus={isNewNote} // Autofocus on title for a new note
            />
          ) : (
            <h2 className="text-3xl font-bold text-gray-800 mb-4">
              {note.title || 'Untitled Note'}
            </h2>
          )}

          {/* Content Input/Display */}
          {isEditing ? (
            <textarea
              value={editedContent}
              onChange={(e) => setEditedContent(e.target.value)}
              className="w-full h-64 p-4 text-gray-800 border-2 border-gray-200 rounded-lg focus:border-indigo-500 outline-none resize-none transition-colors"
              placeholder="Start writing your note here..."
            />
          ) : (
            <div className="min-h-[16rem] bg-gray-50 p-4 rounded-lg overflow-y-auto">
              <p className="text-gray-700 mb-2 whitespace-pre-wrap leading-relaxed">
                {note.content}
              </p>
            </div>
          )}

          {/* Buttons */}
          <div className="flex space-x-4 mt-6">
            {isEditing ? (
              <>
                <button
                  onClick={handleSave}
                  className="flex-1 bg-green-600 text-white py-3 px-6 rounded-xl font-bold hover:bg-green-700 transition-colors shadow-md"
                >
                  {isNewNote ? 'Create Note' : 'Save Changes'}
                </button>
                <button
                  onClick={handleCancel}
                  className="flex-1 bg-gray-200 text-gray-700 py-3 px-6 rounded-xl font-bold hover:bg-gray-300 transition-colors shadow-md"
                >
                  {isNewNote ? 'Discard' : 'Cancel Edit'}
                </button>
              </>
            ) : (
              <button
                onClick={() => setIsEditing(true)}
                className="flex-1 bg-indigo-600 text-white py-3 px-6 rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-md"
              >
                Edit Note
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default NoteModal;
